import{_ as I,c as g,o as i,a1 as t}from"./chunks/framework.mNpZ2GHZ.js";const C="data:image/svg+xml;base64,",D=JSON.parse('{"title":"ReAct 循环","description":"","frontmatter":{},"headers":[],"relativePath":"fe/ai/agent/concept/react.md","filePath":"fe/ai/agent/concept/react.md","lastUpdated":1778229369000}'),d={name:"fe/ai/agent/concept/react.md"},a=t('<h1 id="react-循环" tabindex="-1">ReAct 循环 <a class="header-anchor" href="#react-循环" aria-label="Permalink to &quot;ReAct 循环&quot;">​</a></h1><p>Reasoning + Acting，思考、行动、观察的循环，Agent 核心执行模式。</p><p>2022 年论文：<a href="https://arxiv.org/abs/2210.03629" target="_blank" rel="noreferrer">ReAct: Synergizing Reasoning and Acting in Language Models</a></p><h2 id="核心流程" tabindex="-1">核心流程 <a class="header-anchor" href="#核心流程" aria-label="Permalink to &quot;核心流程&quot;">​</a></h2><p><img src="'+C+'" alt=""></p><ol><li>输入提示词，LLM 思考下一步动作</li><li>调用工具、执行动作，得到输出结果</li><li>观察结果、输入给下一轮思考</li><li>终止条件：LLM 认为任务完成，或触发约束 (最大轮数/预算耗尽/无新进展)</li></ol><h2 id="终止条件" tabindex="-1">终止条件 <a class="header-anchor" href="#终止条件" aria-label="Permalink to &quot;终止条件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>条件</th><th>说明</th><th>优先级</th></tr></thead><tbody><tr><td>用户中断</td><td>用户主动停止</td><td>0</td></tr><tr><td>预算耗尽</td><td>达到 token/成本上限，强制停止</td><td>0.5</td></tr><tr><td>超时</td><td>达到端到端时延上限，强制停止</td><td>0.5</td></tr><tr><td>最大轮数</td><td>达到预设的 MaxIterations</td><td>1</td></tr><tr><td>最小轮数</td><td>强制执行指定轮数</td><td>2</td></tr><tr><td>任务完成</td><td>LLM 明确表示任务已完成</td><td>3</td></tr><tr><td>结果收敛</td><td>连续两次观察结果很像，没有新进展</td><td>4</td></tr></tbody></table>',8),l=[a];function c(e,m,A,M,b,o){return i(),g("div",null,l)}const j=I(d,[["render",c]]);export{D as __pageData,j as default};
